import os
import json
import numpy as np
from sentence_transformers import SentenceTransformer
from sklearn.metrics.pairwise import cosine_similarity
from flask import Flask, request, jsonify
from typing import List, Dict

app = Flask(__name__)

# Load the model for embeddings
model = SentenceTransformer('all-MiniLM-L6-v2')

# In-memory vector database
documents = []
embeddings = []

def load_documents(directory: str):
    for filename in os.listdir(directory):
        if filename.endswith('.txt'):
            with open(os.path.join(directory, filename), 'r') as file:
                content = file.read()
                documents.append(content)
                embeddings.append(model.encode(content))

load_documents('company_documents')

def retrieve_relevant_documents(query: str, top_k: int = 5) -> List[str]:
    query_embedding = model.encode(query)
    similarities = cosine_similarity([query_embedding], embeddings)[0]
    top_indices = np.argsort(similarities)[-top_k:][::-1]
    return [documents[i] for i in top_indices]

@app.route('/query', methods=['POST'])
def query():
    user_query = request.json.get('query')
    relevant_docs = retrieve_relevant_documents(user_query)
    
    # Prevent data leakage by ensuring only relevant context is included
    context = "\n\n".join(relevant_docs)
    
    # Here you would integrate with your LLM API
    # For example:
    # response = call_llm_api(context, user_query)
    
    # Mock response for demonstration
    response = f"Response based on context:\n{context}\n\nUser Query: {user_query}"
    
    return jsonify({'response': response})

if __name__ == '__main__':
    app.run(debug=True)